+{
+    const rcutils_uint8_array_t *src_buffer =
+        (const rcutils_uint8_array_t *)src;
+    rcutils_uint8_array_t *dst_buffer = (rcutils_uint8_array_t *)dst;
+
+    UNUSED_ARG(plugin);
+
+    if (RCUTILS_RET_OK != rcutils_uint8_array_copy(dst_buffer, src_buffer))
+    {
+        return RTI_FALSE;
+    }
+
