+void
+rmw_connextdds_release_typecode_cache(
+    RMW_Connext_TypeCodePtrSeq *const tc_cache)
+{
+    RMW_Connext_TypeCodePtrSeq_finalize_elements(tc_cache);
+    RMW_Connext_TypeCodePtrSeq_finalize(tc_cache);
+}
